@import url(./reset.css);

:root {
  --color-white: #ffffff;
  --color-accent: #dc56c5;
  --color-bg: #212121;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  outline: none;
}

body {
  margin: 0;
  font-family: "Montserrat", sans-serif;
  font-weight: 400;
  background-image: url("../img/bg-desktop.png");
  background-position: center top;
  background-repeat: no-repeat;
  color: var(--color-white);
  background-color: #0e0e0e;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}
.container {
  width: 100%;
  max-width: 1280px;
  margin: 0 auto;
  padding: 0 10px;
}

/* -- header -- */

.header__container {
  position: relative;
}
.header__logo {
  position: absolute;
  top: 0;
  left: 0;
  width: 239px;
  height: 201px;
  border-radius: 0px 0px 100% 0px;
  backdrop-filter: blur(22px);
  box-shadow: inset 7px 7px 16px rgba(255, 255, 255, 0.3);
}
.header__logo img {
  margin: 40px 0 0 40px;
}
.header__content {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding-bottom: 170px;
}
.header__title {
  padding: 40px 0 52px 0;
  text-align: center;
  font-size: 50px;
  font-weight: 900;
  color: var(--color-accent);
}
.header__search {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 30px;
}
.header__search input {
  padding: 10px 50px 10px 30px;
  width: 270px;
  height: 40px;
  border-radius: 20px;
  font-size: 16px;
  border: none;
}
.header__keyword,
.header__country {
  position: relative;
}
.header__input {
  width: 270px;
  height: 40px;
  border-radius: 20px;
  border: none;
  background: rgba(255, 255, 255, 0.15);
  backdrop-filter: blur(20px);
  color: #fff;
  font-family: "Montserrat", sans-serif;
  font-size: 16px;
}
.header__input::placeholder {
  color: #939393;
}
.header__btn {
  position: absolute;
  right: 30px;
  top: 13px;
  background: none;
  border: none;
  cursor: pointer;
}
.header__country {
  display: flex;
}
.country-dropdown {
  display: none;
  position: absolute;
  top: calc(100% + 6px);
  left: 0;
  right: 0;
  border-radius: 12px;
  backdrop-filter: blur(20px);
  max-height: 220px;
  overflow-y: auto;
  z-index: 100;
}
.country-dropdown.open {
  display: block;
}
.dropdown-item {
  padding: 10px 20px;
  font-size: 14px;
  font-family: "Montserrat", sans-serif;
  color: var(--color-white);
  cursor: pointer;
  transition:
    background 0.15s,
    color 0.15s;
}
.dropdown-item:hover {
  background: #dc56c62a;
  color: var(--color-accent);
}

/* -- main -- */
.main {
  flex: 1;
}
.main__container {
  max-width: 1000px;
}
#message{
  text-align: center;
  font-size: 18px;
  color:#ebebeb;
}
.events-list {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 50px;
}
.event {
  width: 100%;
  max-width: 196px;
  text-align: center;
  cursor: pointer;
}
.event-img {
  width: 100%;
  height: 205px;
  object-fit: cover;
  border-radius: 10px;
}
.event h3 {
  font-size: 16px;
  font-weight: 700;
  padding: 10px 0 5px 0;
  color: var(--color-accent);
}
.event p {
  font-size: 16px;
  color: #ffffff;
  padding: 5px 0;
}
.event p:last-child {
  font-size: 14px;
  font-weight: 800;
}
.event-venues::before {
  content: "";
  display: inline-block;
  width: 7px;
  height: 10px;
  margin-right: 5px;
  background-image: url("../img/location.svg");
  background-repeat: no-repeat;
}

/* -- footer -- */
.footer__text {
  text-align: center;
  font-size: 16px;
  color: #939393;
  padding-top: 80px;
  padding-bottom: 19px;
}

/* --- */

@media (max-width: 1200px) {
  body {
    background-image: url("../img/bg-tablet.png");
  }
  .container {
    max-width: 768px;
  }
  .header__logo {
    width: 179px;
    height: 151px;
  }
  .header__logo img {
    max-width: 100px;
    max-height: 50px;
    margin: 30px 0 0 30px;
  }
  .header__title {
    font-size: 30px;
  }
  .header__content {
    padding-bottom: 120px;
  }
  .main__container {
    max-width: 610px;
  }
  .events-list {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 27px;
  }
}
@media (max-width: 768px) {
  body {
    background-image: url("../img/bg-mobile.png");
  }
  .container {
    max-width: 320px;
  }
  .header__logo {
    width: 106px;
    height: 90px;
  }
  .header__logo img {
    max-width: 60px;
    max-height: 60px;
    margin: 20px 0 0 20px;
  }
  .header__title {
    padding: 78px 0px 25px 0;
    font-size: 18px;
  }
  .header__search {
    flex-direction: column;
    gap: 25px;
  }
  .header__content {
    padding-bottom: 70px;
  }
  .main__container {
    max-width: 280px;
  }
  .events-list {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 14px;
  }
  .event-img {
    width: 100%;
    height: 161px;
    object-fit: cover;
    border-radius: 10px;
  }
  .event h3 {
    font-size: 14px;
  }
  .event p {
    font-size: 14px;
  }
  .event p:last-child {
    font-size: 12px;
  }
  .event-venues::before {
    width: 6px;
    height: 9px;
  }
}
